class Solution(object):
    def reverseOnlyLetters(self, s):
        s_list = list(s)
        left, right = 0, len(s) - 1
        while left < right:
            if not s_list[left].isalpha():
                left += 1
            elif not s_list[right].isalpha():
                right -= 1
            else:
                s_list[left], s_list[right] = s_list[right], s_list[left]
                left += 1
                right -= 1
        return ''.join(s_list)
